import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer';
import { HighLowStateParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/HighLowStateParser';

export class HighLowStateEvent extends MessageEvent implements IMessageEvent {
    constructor(callBack: (event: HighLowStateEvent) => void) {
        super(callBack, HighLowStateParser);
    }

    public getParser(): HighLowStateParser {
        return this.parser as HighLowStateParser;
    }
}
